// TestCommitTracker_IgnoresUnrelatedStagedPaths verifies that CommitTracker
// commits only .ddx/beads.jsonl even when the git index contains other staged
// paths (regression: a2b37a405 swept 60+ unrelated paths into the tracker commit).
func TestCommitTracker_IgnoresUnrelatedStagedPaths(t *testing.T) {
	root := initTrackerRepo(t)
	tracker := filepath.Join(root, ".ddx", "beads.jsonl")

	// Modify the tracker so CommitTracker has something to commit.
	require.NoError(t, os.WriteFile(tracker, []byte(`{"id":"ddx-scope-test"}`+"\n"), 0o644))

	// Stage an unrelated 6MB file — simulates lefthook-rejected leftover index state.
	bigFile := filepath.Join(root, "big-unrelated.bin")
	require.NoError(t, os.WriteFile(bigFile, make([]byte, 6*1024*1024), 0o644))
	stageCmd := exec.Command("git", "add", "big-unrelated.bin")
	stageCmd.Dir = root
	stageCmd.Env = scrubbedGitEnvInteg()
	out, err := stageCmd.CombinedOutput()
	require.NoError(t, err, "git add big-unrelated.bin: %s", out)

	// CommitTracker must not sweep the unrelated staged file.
	require.NoError(t, CommitTracker(root))

	// HEAD commit must contain only .ddx/beads.jsonl.
	showCmd := exec.Command("git", "show", "--name-only", "--format=", "HEAD")
	showCmd.Dir = root
	showCmd.Env = scrubbedGitEnvInteg()
	showOut, err := showCmd.CombinedOutput()
	require.NoError(t, err, "git show HEAD: %s", showOut)
	headFiles := strings.TrimSpace(string(showOut))
	require.Equal(t, ".ddx/beads.jsonl", headFiles, "HEAD commit must contain only .ddx/beads.jsonl; got: %q", headFiles)

	// Unrelated file must still be staged (index preserved by --only).
	cachedCmd := exec.Command("git", "diff", "--cached", "--name-only")
	cachedCmd.Dir = root
	cachedCmd.Env = scrubbedGitEnvInteg()
	cachedOut, err := cachedCmd.CombinedOutput()
	require.NoError(t, err, "git diff --cached: %s", cachedOut)
	require.Contains(t, strings.TrimSpace(string(cachedOut)), "big-unrelated.bin",
		"unrelated staged file must remain in the index after CommitTracker")
}

